VALUES
  ('disabled-64311456-moex-00335', 'disabled-64311456', 'disabled-64311456-moex-110-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '有關法務部行政執行署所屬各分署之敘述，下列何者錯誤？', '["為中央四級機關", "因係為中央機關，故其組織仍應以法律定之", "其組織法規應定名為準則", "其內部單位之分工職掌，以辦事細則定之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00336', 'disabled-64311456', 'disabled-64311456-moex-110-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '有關行政法人之敘述，下列何者錯誤？', '["行政法人，指國家及地方自治團體，為執行特定公共事務，依法律或自 治條例設立之公法人", "行政法人應擬訂人事管理、會計制度、內部控制、稽核作業及其他規章， 報請監督機關備查", "行政法人設董（理）事會者，置董（理）事長一人，由董（理）事依章 程選舉產生後聘任", "行政法人設董（理）事會者，得置執行長一人，負責行政法人營運及管 理業務之執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00337', 'disabled-64311456', 'disabled-64311456-moex-110-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '有關地方自治團體與上級監督機關之敘述，下列何者錯誤？', '["地方自治團體之違法行政處分，得由自治監督機關予以撤銷、變更、廢 止或停止其執行", "地方自治團體依法應作為而不作為，致嚴重危害公益或妨礙地方政務正 常運作，其適於代行處理者，得分別由監督機關命其於一定期限內為之", "地方自治團體對監督機關所命其於一定期限內履行職務之處分如認為 窒礙難行時，應向行政法院請求暫停執行該處分", "直轄市政府辦理自治事項違背憲法、法律或基於法律授權之法規者，由 中央各該主管機關報行政院予以撤銷、變更、廢止或停止其執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00338', 'disabled-64311456', 'disabled-64311456-moex-110-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於管轄法定原則之敘述，下列何者錯誤？', '["設定行政機關管轄權之法規不包括行政規則", "行政機關不得與人民以合意方式設定管轄權", "行政機關僅得依法規將權限移轉予其他機關", "行政機關僅得因法規修正而喪失原有管轄權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00339', 'disabled-64311456', 'disabled-64311456-moex-110-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '數行政機關對於同一事件均有管轄權時，依行政程序法規定，下列敘述何 者正確？', '["數行政機關得共同作成行政行為", "先由各行政機關協議決定管轄機關", "先由各行政機關之共同上級機關指定管轄機關", "有為緊急行為之必要時，為必要職務行為之機關應通知其他機關"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00340', 'disabled-64311456', 'disabled-64311456-moex-110-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於職務協助之敘述，下列何者正確？', '["職務協助具有臨時性、被動性與輔助性，並強調共同一體之行政機能", "職務協助與權限之委任或委託相同，均涉及管轄權之變更或移轉", "執行職務所需資料為他機關所有，請求機關應依政府資訊公開法請求之", "於職務協助之情形，被請求機關所持有之資料，並無個人資料保護法之 適用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00341', 'disabled-64311456', 'disabled-64311456-moex-110-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '依公務人員考績法規定，公務人員遭專案考績一次記二大過處分，其法律 效果為何？', '["免職，但得與平時考核功過相抵銷", "免職，且不得與平時考核功過相抵銷", "年終考績應列丙等，但得與平時考核功過相抵銷", "年終考績應列丙等，且不得與平時考核功過相抵銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00342', 'disabled-64311456', 'disabled-64311456-moex-110-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '依公務人員保障法規定，關於公務人員辭職之敘述，下列何者錯誤？', '["辭職為公務人員之權利，服務機關或上級機關應以同意公務人員辭職為 原則", "公務人員於停職事由消滅後，經有權機關查催未申請復職者，除有不可 抗力事由外，視為辭職", "公務人員辭職為要式行為，必須以書面為之", "公務人員提出辭職次日起 30 日內未獲得准駁決定，視為同意辭職，並 一律以其指定離職日為辭職生效日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00343', 'disabled-64311456', 'disabled-64311456-moex-110-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '懲戒法院對公務員作成免除職務之懲戒處分，其懲戒權行使期間為多久？', '["無期間之限制", "10年", "5年", "3年"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:42+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
